import{c as t,Q as l,j as i,m as e}from"./chunks/framework.BIBjCrbN.js";const b=JSON.parse('{"title":"关于本站","description":"网站目的、申请人简介与学术背景","frontmatter":{"title":"关于本站","description":"网站目的、申请人简介与学术背景"},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1780110618000}'),o={name:"about.md"};function r(n,a,s,d,h,u){return l(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="关于本站" tabindex="-1">关于本站 <a class="header-anchor" href="#关于本站" aria-label="Permalink to &quot;关于本站&quot;">​</a></h1><h2 id="网站目的" tabindex="-1">网站目的 <a class="header-anchor" href="#网站目的" aria-label="Permalink to &quot;网站目的&quot;">​</a></h2><p>本站为个人整理的 <strong>2026年秋季入学中国博士申请一站式信息平台</strong>，旨在系统性地汇总中国顶尖高校在神经工程、生物医学工程及相关方向的博士招生信息。</p><p><strong>建设目标</strong>：</p><ul><li>一站式查阅目标院校的导师信息、研究方向、申请流程</li><li>按研究方向交叉索引，快速定位匹配的导师</li><li>跟踪2026年秋季入学的关键申请时间节点</li><li>所有信息标注来源，链接可追溯、可验证</li></ul><h2 id="申请人简介" tabindex="-1">申请人简介 <a class="header-anchor" href="#申请人简介" aria-label="Permalink to &quot;申请人简介&quot;">​</a></h2><h3 id="教育背景" tabindex="-1">教育背景 <a class="header-anchor" href="#教育背景" aria-label="Permalink to &quot;教育背景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>学位</th><th>学校</th><th>时间</th><th>专业</th></tr></thead><tbody><tr><td>硕士</td><td>帝国理工学院 (Imperial College London) 生物医学工程（神经技术方向）硕士</td><td>伦敦大学学院 (University College London) 医用物理 本科</td><td></td></tr></tbody></table><h3 id="研究经历" tabindex="-1">研究经历 <a class="header-anchor" href="#研究经历" aria-label="Permalink to &quot;研究经历&quot;">​</a></h3><ul><li><strong>脑类器官自发性活动与温度影响研究</strong>（硕士期间）— 开发集成温控的双光子显微镜成像系统，研究iPSC衍生神经类器官的钙信号动态</li><li><strong>超声治疗系统GUI评估</strong>（UCL暑期RA）— HIFU治疗系统校准、性能验证与用户指南编写</li><li><strong>可穿戴肌电听觉生物反馈系统</strong>（本科项目）— 自主设计EMG信号采集与实时音频反馈原型</li></ul><h3 id="研究兴趣" tabindex="-1">研究兴趣 <a class="header-anchor" href="#研究兴趣" aria-label="Permalink to &quot;研究兴趣&quot;">​</a></h3><ul><li>脑机接口与神经工程</li><li>系统神经科学（听觉/感觉系统）</li><li>神经退行性疾病模型（iPSC/类器官）</li><li>神经信号处理与计算建模</li></ul><h3 id="技术技能" tabindex="-1">技术技能 <a class="header-anchor" href="#技术技能" aria-label="Permalink to &quot;技术技能&quot;">​</a></h3><ul><li><strong>编程</strong>：Python、MATLAB、Arduino</li><li><strong>实验</strong>：钙成像、双光子/共聚焦显微镜、EMG信号采集、免疫组化、细胞培养</li><li><strong>设备</strong>：超声系统校准、电路设计、传感器集成</li></ul><h2 id="数据来源声明" tabindex="-1">数据来源声明 <a class="header-anchor" href="#数据来源声明" aria-label="Permalink to &quot;数据来源声明&quot;">​</a></h2><p>本站所有信息来源于以下渠道（按优先级排序）：</p><ol><li>各院校研究生院/学院官网公告</li><li>导师个人主页（.edu.cn 域名）</li><li>中国知网 (CNKI)、PubMed、Google Scholar</li><li>官方微信公众号/通知公告</li></ol><p>所有外部链接均标注访问日期。信息具有一定时效性，请以各校官方最新公告为准。</p><h2 id="更新计划" tabindex="-1">更新计划 <a class="header-anchor" href="#更新计划" aria-label="Permalink to &quot;更新计划&quot;">​</a></h2><ul><li><strong>2026年5月</strong>：初版上线，覆盖2026秋季入学信息</li><li><strong>2026年8月</strong>：更新为2027年入学申请季信息</li><li><strong>持续更新</strong>：补充新发现的导师和实验室信息</li></ul>',20)])])}const g=t(o,[["render",r]]);export{b as __pageData,g as default};
